#!/usr/bin/env python3
import argparse, json, shutil, tempfile
from pathlib import Path
from tools.incident_closure.soil._incident_closure_common import *
def main(argv=None):
 ap=argparse.ArgumentParser();
 for k in ['incident','observability','delivery','routing','active','lineage','outcome','remediation','corrective','resolution','accountability','assurance','registry','certification','archive','preservation','reconciliation','federation','discovery','published','ops','closure','out']:
  ap.add_argument(f'--{k}-root',required=True)
 ap.add_argument('--incident-response-id'); ap.add_argument('--closure-id'); ap.add_argument('--base-public-url',required=True)
 a=ap.parse_args(argv)
 if not validate_base_public_url(a.base_public_url): print(json.dumps({'incident_closure_allowed':False,'reasons':['bad base-public-url']})); return 1
 irid=a.incident_response_id or load_current_delivery_incident_response(a.incident_root)['active_incident_response_id']
 im=load_delivery_incident_response_manifest(a.incident_root,irid); ir=load_delivery_incident_response_receipt(a.incident_root,irid)
 incidents=load_delivery_incident_declaration_registry(a.incident_root,irid).get('incidents',[])
 closures_dir=Path(a.closure_root)/'incident_closure/soil/closures'/irid; safe_dir=Path(a.closure_root)/'incident_closure/soil/safe_mode'/irid
 closures=sorted(closures_dir.glob('*.incident_closure_decision.json')) if closures_dir.exists() else []
 apps=sorted(safe_dir.glob('*.safe_mode_exit_approval.json')) if safe_dir.exists() else []
 if incidents and not closures: print(json.dumps({'incident_closure_allowed':False,'incident_response_id':irid,'reasons':['missing closure decision']})); return 1
 cid=sanitize_id(a.closure_id or ('soil-closure-'+hashlib.sha256((''.join([sha256_file(p) for p in closures+apps])+irid).encode()).hexdigest()[:16]))
 out=Path(a.out_root)/'incident_closure/soil/cycles'/cid
 if out.exists(): print(json.dumps({'incident_closure_allowed':False,'incident_response_id':irid,'reasons':['closure directory exists']})); return 1
 tdir=Path(tempfile.mkdtemp(prefix='kfm_closure_'))/cid; tdir.mkdir(parents=True,exist_ok=True)
 state='no_active_incident' if not incidents else ('closed_recovered' if apps else 'open_governance_only')
 allowed=state=='closed_recovered' or state=='no_active_incident'
 manifest={'schema_version':'kfm.v1','object_type':'SoilDeliveryIncidentClosureManifest','domain':'soil','closure_id':cid,'incident_response_id':irid,'observability_id':im.get('observability_id'),'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'pointer_transition_id':im.get('pointer_transition_id'),'lineage_id':im.get('lineage_id'),'outcome_cycle_id':im.get('outcome_cycle_id'),'remediation_id':im.get('remediation_id'),'corrective_id':im.get('corrective_id'),'resolution_id':im.get('resolution_id'),'accountability_id':im.get('accountability_id'),'assurance_id':im.get('assurance_id'),'registry_id':im.get('registry_id'),'certification_id':im.get('certification_id'),'archive_package_id':im.get('archive_package_id'),'preservation_id':im.get('preservation_id'),'reconciliation_id':im.get('reconciliation_id'),'federation_id':im.get('federation_id'),'discovery_id':im.get('discovery_id'),'prior_release_id':im.get('prior_release_id'),'active_release_id':im.get('active_release_id'),'publication_status':'PUBLISHED','incident_response_status':'PUBLIC_DELIVERY_INCIDENT_RESPONSE_READY','incident_closure_status':'PUBLIC_DELIVERY_INCIDENT_CLOSURE_READY','closure_state':state,'certificate_status':im.get('certificate_status','active'),'active_public_routes_enabled':im.get('active_public_routes_enabled',False),'active_public_delivery_allowed_after_closure':allowed,'created':utc_now_iso(),'base_public_url':a.base_public_url}
 files={'delivery_incident_closure_manifest.json':manifest,'post_incident_review_dossier.json':{'schema_version':'kfm.v1','object_type':'SoilPostIncidentReviewDossier','domain':'soil','closure_id':cid,'incident_response_id':irid,'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'sections':[]},'root_cause_classification_registry.json':{'schema_version':'kfm.v1','object_type':'SoilRootCauseClassificationRegistry','domain':'soil','closure_id':cid,'incident_response_id':irid,'classifications':[]},'recovery_closure_verification_registry.json':{'schema_version':'kfm.v1','object_type':'SoilRecoveryClosureVerificationRegistry','domain':'soil','closure_id':cid,'incident_response_id':irid,'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'recovery_verified':allowed,'verifications':[]},'safe_mode_exit_recommendation_packet.json':{'schema_version':'kfm.v1','object_type':'SoilSafeModeExitRecommendationPacket','domain':'soil','closure_id':cid,'incident_response_id':irid,'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'active_release_id':im.get('active_release_id'),'safe_mode_exit_state':'allow_active_delivery' if allowed else 'remain_governance_only','active_public_delivery_allowed_after_closure':allowed,'recommendations':[]},'resilience_control_update_plan.json':{'schema_version':'kfm.v1','object_type':'SoilResilienceControlUpdatePlan','domain':'soil','closure_id':cid,'incident_response_id':irid,'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'control_updates':[],'controls_update_required':False,'future_assurance_update_required':False,'future_observability_update_required':False},'public_post_incident_report.json':{'schema_version':'kfm.v1','object_type':'SoilPublicPostIncidentReport','domain':'soil','closure_id':cid,'incident_response_id':irid,'observability_id':im.get('observability_id'),'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'pointer_transition_id':im.get('pointer_transition_id'),'prior_release_id':im.get('prior_release_id'),'active_release_id':im.get('active_release_id'),'incident_closure_status':'PUBLIC_DELIVERY_INCIDENT_CLOSURE_READY','closure_state':state,'certificate_status':im.get('certificate_status','active'),'active_public_routes_enabled':im.get('active_public_routes_enabled',False),'active_public_delivery_allowed_after_closure':allowed,'safe_mode_exit_state':'allow_active_delivery' if allowed else 'remain_governance_only','incident_count':len(incidents),'closed_incident_count':len(incidents) if allowed else 0,'open_incident_count':0 if allowed else len(incidents),'recovery_verified':allowed,'resilience_controls_update_required':False,'public_summary':'Deterministic incident closure completed.','recommended_public_action':'none' if allowed else 'remain_governance_only'},'incident_closure_transparency_log.json':{'schema_version':'kfm.v1','object_type':'SoilIncidentClosureTransparencyLog','domain':'soil','closure_id':cid,'incident_response_id':irid,'entries':[],'log_root':None,'created':utc_now_iso()}}
 for k,v in files.items(): write_json_atomic(tdir/k,v)
 hashes={k:sha256_file(tdir/k) for k in files}
 receipt={'schema_version':'kfm.v1','receipt_type':'DeliveryIncidentClosureReceipt','from_state':'PUBLIC_DELIVERY_INCIDENT_RESPONSE_READY','to_state':'PUBLIC_DELIVERY_INCIDENT_CLOSURE_READY','decision':'pass' if allowed else 'governance_only','domain':'soil','prior_release_id':im.get('prior_release_id'),'active_release_id':im.get('active_release_id'),'incident_response_id':irid,'closure_id':cid,'created':utc_now_iso(),'raw_access_logs_publicly_exposed':False,'published_current_pointer_mutated':False,'immutable_artifacts_mutated':False,'generated_artifacts':hashes,'signatures':[{'dsse':'PROPOSED-COSIGN','key_ref':'kfm://keys/ci'}],'source_delivery_incident_response_receipt':{'ref':f'incident_response/soil/cycles/{irid}/delivery_incident_response_receipt.json','sha256':stable_payload_hash(ir)}}
 write_json_atomic(tdir/'delivery_incident_closure_receipt.json',receipt)
 out.parent.mkdir(parents=True,exist_ok=True); shutil.move(str(tdir),str(out))
 cur={'schema_version':'kfm.v1','object_type':'SoilCurrentDeliveryIncidentClosurePointer','domain':'soil','active_closure_id':cid,'incident_response_id':irid,'observability_id':im.get('observability_id'),'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'pointer_transition_id':im.get('pointer_transition_id'),'lineage_id':im.get('lineage_id'),'prior_release_id':im.get('prior_release_id'),'active_release_id':im.get('active_release_id'),'incident_closure_status':'PUBLIC_DELIVERY_INCIDENT_CLOSURE_READY','closure_state':state,'active_public_delivery_allowed_after_closure':allowed,'delivery_incident_closure_manifest_ref':f'incident_closure/soil/cycles/{cid}/delivery_incident_closure_manifest.json','delivery_incident_closure_receipt_ref':f'incident_closure/soil/cycles/{cid}/delivery_incident_closure_receipt.json','created':utc_now_iso()}
 write_json_atomic(Path(a.out_root)/'incident_closure/soil/current_delivery_incident_closure.json',cur)
 print(json.dumps({'incident_closure_allowed':True,'closure_id':cid,'incident_response_id':irid,'observability_id':im.get('observability_id'),'delivery_id':im.get('delivery_id'),'routing_id':im.get('routing_id'),'prior_release_id':im.get('prior_release_id'),'active_release_id':im.get('active_release_id'),'state_transition':'PUBLIC_DELIVERY_INCIDENT_RESPONSE_READY->PUBLIC_DELIVERY_INCIDENT_CLOSURE_READY','closure_state':state,'outputs':cur}))
 return 0
if __name__=='__main__': raise SystemExit(main())
